import { ButtonVariant } from './button';
export interface IxButtonComponent {
    /**
     * Annotate with @Prop() decorator
     */
    variant: ButtonVariant;
    /**
     * Annotate with @Prop() decorator
     */
    outline: boolean;
    /**
     * Annotate with @Prop() decorator
     */
    ghost: boolean;
    /**
     * Annotate with @Prop({ reflect: true }) decorator
     */
    disabled: boolean;
    /**
     * Annotate with @Prop() decorator
     */
    type: 'button' | 'submit';
    /**
     * Annotate with @Prop() decorator
     */
    loading: boolean;
    /**
     * Annotate with @Prop() decorator
     */
    icon?: string;
}
